input.new_string:
const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const quoteItems = (items: Item[]): number => {
  const base = items.reduce((sum, item) => sum + (BASE_PREMIUM[item.type] ?? 0), 0);
  const withFirstInsurance = base * 1.10;
  return Math.ceil(withFirstInsurance) + 5;
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results: Result[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      return { premium: quoteItems(step.items) };
    }
    return { payout: 0 };
  });
  return { results };
};

