import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote: base prices per item type
  it("quotes a sword for a new customer (base price + processing fee + first-insurance surcharge)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("quotes an amulet, staff, and potion correctly", () => {
    const quoteOne = (type: string): number => {
      const r = runScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [{ type, material: "x", enchantment: 1, cursed: false }] }],
      });
      return (r.results[0] as { premium: number }).premium;
    };
    expect(quoteOne("amulet")).toBe(71);
    expect(quoteOne("staff")).toBe(93);
    expect(quoteOne("potion")).toBe(49);
  });
  it.todo("quotes a single component (rune) at 25 G base");
  it.todo("quotes 3 alike components as a building block at 60 G base");
  it.todo("quotes 4 alike components as one building block plus one single");

  // Quote: modifiers
  it.todo("applies 50% surcharge for a cursed item");
  it.todo("applies 30% surcharge for an item with enchantment level >= 5");
  it.todo("applies 20% loyalty discount for customers with >= 2 years");
  it.todo("applies 15% multi-contract discount on contracts after the first");
  it.todo("rounds the total premium up (in MHPCO's favor)");

  // Claim: payouts
  it.todo("pays 0 when total damage does not exceed the 100 G deductible");
  it.todo("pays damage minus 100 G deductible for ordinary items");
  it.todo("pays 50% of damage (minus deductible) for items with enchantment >= 8");
  it.todo("pays full damage (minus deductible) for items made of dragon material");

  // CLI / scenario orchestration
  it.todo("runs a scenario with a quote followed by a claim against that policy");
});

