const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BUILDING_BLOCK_PREMIUM = 60;
const FIRST_INSURANCE_SURCHARGE = 0.10;
const PROCESSING_FEE = 5;

const ceilG = (amount: number): number => Math.ceil(amount - 1e-9);

const basePremiumForItems = (items: Item[]): number => {
  const componentCounts: Record<string, number> = {};
  let total = 0;
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      total += BASE_PREMIUM[item.type] ?? 0;
    }
  }
  for (const type of Object.keys(componentCounts)) {
    const count = componentCounts[type];
    const blocks = Math.floor(count / 3);
    const remainder = count % 3;
    total += blocks * BUILDING_BLOCK_PREMIUM + remainder * BASE_PREMIUM[type];
  }
  return total;
};

const quoteItems = (items: Item[]): number => {
  const base = basePremiumForItems(items);
  const withFirstInsurance = base * (1 + FIRST_INSURANCE_SURCHARGE);
  return ceilG(withFirstInsurance) + PROCESSING_FEE;
};

