    expect(quoteOne("potion")).toBe(49);
  });
  it("quotes a single component (rune) at 25 G base", () => {
    const r = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }] }],
