      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", cursed: true }] }],
    });
    expect(r).toEqual({ results: [{ premium: 170 }] });
  });
  it.todo("applies 30% surcharge for an item with enchantment level >= 5");
  it.todo("applies 20% loyalty discount for customers with >= 2 years");
  it.todo("applies 15% multi-contract discount on contracts after the first");
